-- ─────────────────────────────────────────────────────────────────────────────
-- TCS (Toronto Chinese Services) — Database Schema
-- Engine : PostgreSQL 15+
-- Convention: All primary keys are UUID (GUID), generated by the database.
--             All timestamps are TIMESTAMPTZ (timezone-aware).
-- Safe to run multiple times — all statements use IF NOT EXISTS guards.
-- ─────────────────────────────────────────────────────────────────────────────


-- ─── EXTENSION ───────────────────────────────────────────────────────────────
CREATE EXTENSION IF NOT EXISTS "pgcrypto";


-- ─────────────────────────────────────────────────────────────────────────────
-- TABLE: users
-- ─────────────────────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS users (
  id              UUID          PRIMARY KEY DEFAULT gen_random_uuid(),

  name            VARCHAR(100)  NOT NULL,
  email           VARCHAR(255)  UNIQUE NOT NULL,
  phone           VARCHAR(30),
  wechat          VARCHAR(100),
  avatar_url      TEXT,
  social_links    JSONB         DEFAULT '{}',

  password_hash   TEXT,
  is_email_verified BOOLEAN     DEFAULT false,
  phone_verified    BOOLEAN     DEFAULT false,

  role            VARCHAR(20)   DEFAULT 'user'
                  CHECK (role IN ('user', 'provider', 'admin')),

  created_at      TIMESTAMPTZ   DEFAULT NOW(),
  updated_at      TIMESTAMPTZ   DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_users_email ON users (email);


-- ─────────────────────────────────────────────────────────────────────────────
-- TABLE: categories
-- ─────────────────────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS categories (
  id          VARCHAR(30)   PRIMARY KEY,
  label       VARCHAR(50)   NOT NULL,
  description TEXT,
  image_path  TEXT,
  sort_order  INT           DEFAULT 0
);

